455	json common_chat_msg_diff_to_json_oaicompat(const common_chat_msg_diff & diff) {
456	    json delta = json::object();
457	    if (!diff.reasoning_content_delta.empty()) {
458	        delta["reasoning_content"] = diff.reasoning_content_delta;
459	    }
460	    if (!diff.content_delta.empty()) {
461	        delta["content"] = diff.content_delta;
462	    }
463	    if (diff.tool_call_index != std::string::npos) {
464	        json tool_call;
465	        tool_call["index"] = diff.tool_call_index;
466	        if (!diff.tool_call_delta.id.empty()) {
467	            tool_call["id"]   = diff.tool_call_delta.id;
468	            tool_call["type"] = "function";
469	        }
470	        if (!diff.tool_call_delta.name.empty() || !diff.tool_call_delta.arguments.empty()) {
471	            json function = json::object();
472	            if (!diff.tool_call_delta.name.empty()) {
473	                function["name"] = diff.tool_call_delta.name;
474	            }
475	            if (!diff.tool_call_delta.arguments.empty()) {
476	                function["arguments"] = diff.tool_call_delta.arguments;
477	            }
478	            tool_call["function"] = function;
479	        }
480	        delta["tool_calls"] = json::array({ tool_call });
481	    }
482	    return delta;
483	}
