1634	std::optional<common_chat_params> common_chat_try_specialized_template(
1635	        const common_chat_template &          tmpl,
1636	        const std::string &                   src,
1637	        const autoparser::generation_params & params) {
1638	    // Ministral/Mistral Large 3 - uses special reasoning structure fixes, can't use autoparser
1639	    // Note: Mistral Small 3.2 uses [CALL_ID] which Ministral doesn't have, so we can distinguish them
1640	    if (src.find("[SYSTEM_PROMPT]") != std::string::npos && src.find("[TOOL_CALLS]") != std::string::npos &&
1641	        src.find("[ARGS]") != std::string::npos && src.find("[CALL_ID]") == std::string::npos) {
1642	        LOG_DBG("Using specialized template: Ministral/Magistral Large 3\n");
1643	        return common_chat_params_init_ministral_3(tmpl, params);
1644	    }
1645	
1646	    // GPT-OSS - has unique channel-based structure that needs dedicated handler
1647	    if (src.find("<|channel|>") != std::string::npos) {
1648	        LOG_DBG("Using specialized template: GPT-OSS\n");
1649	        return common_chat_params_init_gpt_oss(tmpl, params);
1650	    }
1651	
1652	    // Functionary v3.2 - uses recipient-based format with >>>recipient\n{content}
1653	    // Detection: template has ">>>all" for content and ">>>" prefix for tool calls
1654	    if (src.find(">>>all") != std::string::npos && src.find(">>>${recipient}") != std::string::npos) {
1655	        LOG_DBG("Using specialized template: Functionary v3.2\n");
1656	        return common_chat_params_init_functionary_v3_2(tmpl, params);
1657	    }
1658	
1659	    // Kimi K2 Thinking - uses unique tool call ID format: functions.<name>:<index>
1660	    // Detection: template has "<|tool_calls_section_begin|>" and "functions." prefix in tool call IDs
1661	    if (src.find("<|tool_calls_section_begin|>") != std::string::npos &&
1662	        src.find("<|tool_call_begin|>") != std::string::npos) {
1663	        LOG_DBG("Using specialized template: Kimi K2 Thinking\n");
1664	        return common_chat_params_init_kimi_k2(tmpl, params);
1665	    }
1666	
1667	    // LFM2 format detection: template uses <|tool_list_start|>[...]<|tool_list_end|> around the tool list
1668	    // and <|tool_call_start|>[...]<|tool_call_end|> around each tool call
1669	    if (src.find("<|tool_list_start|>") != std::string::npos &&
1670	        src.find("<|tool_list_end|>") != std::string::npos) {
1671	        LOG_DBG("Using specialized template: LFM2\n");
1672	        return common_chat_params_init_lfm2(tmpl, params);
1673	    }
1674	
1675	    // LFM2.5 format detection: template uses plain "List of tools: [...]" with no special tokens
1676	    if (src.find("List of tools: [") != std::string::npos &&
1677	        src.find("<|tool_list_start|>") == std::string::npos) {
1678	        LOG_DBG("Using specialized template: LFM2.5\n");
1679	        return common_chat_params_init_lfm2_5(tmpl, params);
1680	    }
1681	
1682	    // GigaChatV3 format detection
1683	    if (src.find("<|role_sep|>") != std::string::npos &&
1684	        src.find("<|message_sep|>") != std::string::npos &&
1685	        src.find("<|function_call|>") == std::string::npos) {
1686	        LOG_DBG("Using specialized template: GigaChatV3\n");
1687	        return common_chat_params_init_gigachat_v3(tmpl, params);
1688	    }
1689	
1690	    return std::nullopt;
1691	}
